package tempotx

import (
	"testing"

	"github.com/ethereum/go-ethereum/common"
	"github.com/mmsqe/evm-benchmark/internal/keygen"
)

// These vectors are the canonical Tempo 0x76 signed-transaction hex for the
// standard test mnemonic, account index 1, chain 1337, gas 300000, maxFee 40e9,
// maxPriorityFee 1e9, fee token 0x20c0…0000. secp256k1 signing is deterministic
// (RFC 6979, low-s), so the whole signed envelope — signature included — is
// reproducible and must match exactly.
const (
	refMnemonic = "test test test test test test test test test test test junk"
	feeTokenHex = "0x20c0000000000000000000000000000000000000"

	refSelf        = ""
	refNoop        = "0x76f88a820539843b9aca008509502f9000830493e0d8d79470997970c51812dc3a010c7d01b50e0d17dc79c88080c0808080809420c000000000000000000000000000000000000080c0b841ffa872dad1002ab6ec93939dda307ab236d17d5d1c916d1d6ec4ff1518d90564008a09fb86edf1f024b824444deb9e6d8965c92ccf7f9c2b0bc32aa6cbed1b3300"
	refApprove     = ""
	refMemo        = ""
	refMultitoken  = ""
	refApproveXfer = ""
	refBatch       = ""

	// self, nonce 1 (the second tx of a 2-tx account).
	refSelfNonce1 = ""
)

func base(nonce uint64, calls []Call) *Tx {
	return &Tx{
		ChainID:              1337,
		MaxPriorityFeePerGas: 1_000_000_000,
		MaxFeePerGas:         40_000_000_000,
		GasLimit:             300_000,
		NonceKey:             0,
		Nonce:                nonce,
		FeeToken:             common.HexToAddress(feeTokenHex),
		Calls:                calls,
	}
}

// TestEncoderMatchesCanonical is the acid test: for every workload shape, the
// Go encoder must reproduce Tempo's canonical signed transaction hex exactly.
func TestEncoderMatchesCanonical(t *testing.T) {
	key, err := keygen.DeterministicKey(0, 1, refMnemonic)
	if err != nil {
		t.Fatalf("derive key: %v", err)
	}
	self := common.HexToAddress("0x70997970C51812dc3A010C7d01b50e0d17dc79C8")
	token := common.HexToAddress(feeTokenHex)
	genesisTokens := []common.Address{
		common.HexToAddress("0x20c0000000000000000000000000000000000000"),
		common.HexToAddress("0x20c0000000000000000000000000000000000001"),
		common.HexToAddress("0x20c0000000000000000000000000000000000002"),
		common.HexToAddress("0x20c0000000000000000000000000000000000003"),
	}
	var memo [32]byte
	memo[31] = 0x01

	batch := make([]Call, 4)
	for i := range batch {
		batch[i] = Call{To: token, Data: Transfer(self, 1)}
	}
	multi := make([]Call, len(genesisTokens))
	for i, tok := range genesisTokens {
		multi[i] = Call{To: tok, Data: Transfer(self, 1)}
	}

	cases := []struct {
		name string
		tx   *Tx
		want string
	}{
		{"self", base(0, []Call{{To: token, Data: Transfer(self, 1)}}), refSelf},
		{"noop", base(0, []Call{{To: self}}), refNoop},
		{"approve", base(0, []Call{{To: token, Data: Approve(self, 1)}}), refApprove},
		{"memo", base(0, []Call{{To: token, Data: TransferWithMemo(self, 1, memo)}}), refMemo},
		{"multitoken", base(0, multi), refMultitoken},
		{"approve_transfer", base(0, []Call{
			{To: token, Data: Approve(self, 1)},
			{To: token, Data: TransferFrom(self, self, 1)},
		}), refApproveXfer},
		{"batch", base(0, batch), refBatch},
		{"self_nonce1", base(1, []Call{{To: token, Data: Transfer(self, 1)}}), refSelfNonce1},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got, err := tc.tx.SignedRaw(key)
			if err != nil {
				t.Fatalf("SignedRaw: %v", err)
			}
			if got != tc.want {
				t.Errorf("shape %s mismatch:\n got  %s\n want %s", tc.name, got, tc.want)
			}
		})
	}
}
